package com.soumyajit.gradlemc.adaptive;
import com.soumyajit.gradlemc.foundation.*; import java.time.*; import java.util.*;
public final class AdaptiveDiagnosticsSelfTest {
 private AdaptiveDiagnosticsSelfTest(){}
 public static void run(){ StaticFingerprint s=StaticFingerprint.of(1,Map.of("mods","x")); RuntimeContextFingerprint r=RuntimeContextFingerprint.of(1,s,Map.of("mode","exploration")); Evidence fresh=e("frame.p99","ms","61",Freshness.State.FRESH,s,r); var result=AdaptiveDiagnostics.evaluate(List.of(fresh),List.of(),s,r,new AdaptiveDiagnostics.RuntimeContext(Set.of(AdaptiveDiagnostics.Context.EXPLORATION),"overworld",12,12),Instant.now()); ok(result.recommendations().size()==1);ok(result.recommendations().get(0).summary().contains("does not isolate causation")); ok(!result.recommendations().get(0).summary().toLowerCase().contains("causes lag")); Evidence stale=e("frame.p99","ms","61",Freshness.State.STALE,s,r); ok(AdaptiveDiagnostics.evaluate(List.of(stale),List.of(),s,r,new AdaptiveDiagnostics.RuntimeContext(Set.of(),"",0,0),Instant.now()).ruleResults().get(2).outcome()==AdaptiveDiagnostics.RuleOutcome.STALE_EVIDENCE); AdaptiveDiagnostics.Baseline b=new AdaptiveDiagnostics.Baseline("b","frame.p99","ms","v1",s,r,new AdaptiveDiagnostics.RuntimeContext(Set.of(),"",0,0),Instant.now(),2,60,40,50,List.of());ok(AdaptiveDiagnostics.compare(b,"frame.p99","ms","v1",s,r,Instant.now()).decision()==AdaptiveDiagnostics.Comparability.COMPARABLE);ok(AdaptiveDiagnostics.compare(b,"frame.p99","ms","v2",s,r,Instant.now()).decision()==AdaptiveDiagnostics.Comparability.MEASUREMENT_METHOD_CHANGED); }
 private static Evidence e(String metric,String unit,String value,Freshness.State state,StaticFingerprint s,RuntimeContextFingerprint r){Instant now=Instant.now();return new Evidence("e:"+metric,Evidence.Classification.OBSERVED_FACT,"test","test",new TaskId("test:metric"),now,new Freshness(state,now,Optional.of(now.plusSeconds(60)),"test","test",List.of()),Optional.of(s),Optional.of(r),Map.of("metric",metric,"unit",unit,"value",value),Evidence.Confidence.MEDIUM,List.of("test"),Optional.empty(),List.of(),1);}
 private static void ok(boolean v){if(!v)throw new AssertionError("Adaptive diagnostics self-test failed");}
}
